import{_ as a,o,c as t,ag as n}from"./chunks/framework.DdzuPfYX.js";const p=JSON.parse('{"title":"測試環境與帳號準備 (Environment & Accounts)","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/env-setup.md","filePath":"onboarding/env-setup.md"}'),r={name:"onboarding/env-setup.md"};function i(s,e,l,c,d,u){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="測試環境與帳號準備-environment-accounts" tabindex="-1">測試環境與帳號準備 (Environment &amp; Accounts) <a class="header-anchor" href="#測試環境與帳號準備-environment-accounts" aria-label="Permalink to &quot;測試環境與帳號準備 (Environment &amp; Accounts)&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Onboard 知識點</p><p>本文件涵蓋前端測試環境的存取方式、測試帳號的建立規則，以及執行回歸測試時需準備的軟硬體設備與自動化工具。</p></div><hr><h2 id="一、前端-web-測試環境-test-environments" tabindex="-1">一、前端 Web 測試環境 (Test Environments) <a class="header-anchor" href="#一、前端-web-測試環境-test-environments" aria-label="Permalink to &quot;一、前端 Web 測試環境 (Test Environments)&quot;">​</a></h2><p>QA 團隊在進行前端每週版更或功能驗證時，主要透過 GitHub Pull Request (PR) 產生的專屬測試網址進行。</p><h3 id="_1-取得測試網址" tabindex="-1">1. 取得測試網址 <a class="header-anchor" href="#_1-取得測試網址" aria-label="Permalink to &quot;1. 取得測試網址&quot;">​</a></h3><p>每當前端發起 PR 並完成部署後，GitHub Actions 會自動生成對應版本的測試環境。</p><ul><li><strong>網址格式：</strong> <code>https://{version}.app.swag.live</code> (例如：<code>https://v3-277.app.swag.live</code>)。</li><li><strong>快速存取：</strong> 你可以直接在 GitHub PR 頁面下方，點擊 <code>View deployment</code> 按鈕直接前往該測試站。</li></ul><h3 id="_2-後端資料串接注意事項" tabindex="-1">2. 後端資料串接注意事項 <a class="header-anchor" href="#_2-後端資料串接注意事項" aria-label="Permalink to &quot;2. 後端資料串接注意事項&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">重要警告</p><p>目前前端 Web 測試環境 <strong>串接的後端資料為正式環境 (Production)</strong>。 所有在測試站上的寫入行為（包含發文、私訊、修改資料）皆會同步至正式資料庫。請務必謹慎操作，避免影響真實使用者。</p></div><hr><h2 id="二、測試帳號申請規則-test-accounts" tabindex="-1">二、測試帳號申請規則 (Test Accounts) <a class="header-anchor" href="#二、測試帳號申請規則-test-accounts" aria-label="Permalink to &quot;二、測試帳號申請規則 (Test Accounts)&quot;">​</a></h2><p>為了覆蓋不同的權限漏斗與金流測試，QA 成員必須自備多組測試帳號。</p><h3 id="_1-信箱分身技巧-alias" tabindex="-1">1. 信箱分身技巧 (Alias) <a class="header-anchor" href="#_1-信箱分身技巧-alias" aria-label="Permalink to &quot;1. 信箱分身技巧 (Alias)&quot;">​</a></h3><p>請使用公司配發的 Email 進行申請。利用 Gmail 的加號 <code>+</code> 標籤功能，可以使用同一個信箱註冊無數個測試帳號。</p><ul><li><strong>範例：</strong><ul><li><code>{your.name}+1@swag.live</code></li><li><code>{your.name}+2@swag.live</code></li><li><code>{your.name}+3@swag.live</code></li></ul></li></ul><h3 id="_2-必備的測試帳號層級" tabindex="-1">2. 必備的測試帳號層級 <a class="header-anchor" href="#_2-必備的測試帳號層級" aria-label="Permalink to &quot;2. 必備的測試帳號層級&quot;">​</a></h3><p>每位 QA 至少需準備以下四種層級的帳號，以利完整覆蓋回歸測試：</p><ol><li><strong>一般用戶 (Regular User)：</strong> 全新的白紙帳號，用於測試最標準的訪客與付費轉換流程。</li><li><strong>Beta 用戶 (Beta User)：</strong> 綁定 Beta Tag，用於測試 Live 環境下尚未公開的第三方金流商，或是部分為開放給一般用戶的 features。</li><li><strong>主播 Beta 帳號 (Creator Beta)：</strong> 模擬創作者身分，此類帳號系統設定為「無法消耗鑽石」。</li><li><strong>最高權限用戶 (God Mode/Admin)：</strong> 具備所有解鎖權限，可免費觀看所有付費內容，用於快速驗證內容播放狀態。</li></ol><hr><h2 id="三、測試設備與輔助工具-devices-tools" tabindex="-1">三、測試設備與輔助工具 (Devices &amp; Tools) <a class="header-anchor" href="#三、測試設備與輔助工具-devices-tools" aria-label="Permalink to &quot;三、測試設備與輔助工具 (Devices &amp; Tools)&quot;">​</a></h2><h3 id="_1-硬體設備規範" tabindex="-1">1. 硬體設備規範 <a class="header-anchor" href="#_1-硬體設備規範" aria-label="Permalink to &quot;1. 硬體設備規範&quot;">​</a></h3><ul><li><strong>iOS 裝置：</strong> 無特定機型限制，但每週回歸測試至少需使用 1 台 iOS 實體機進行驗證。</li><li><strong>MDM 企業管理：</strong> 測試機器的安裝與憑證管理流程 (SOP 待補)。</li></ul><h3 id="_2-輔助測試工具" tabindex="-1">2. 輔助測試工具 <a class="header-anchor" href="#_2-輔助測試工具" aria-label="Permalink to &quot;2. 輔助測試工具&quot;">​</a></h3><ul><li><strong>Moor (API 測試)：</strong> 需使用安裝於測試機上的專屬測試 App 進行後端與 API 的交接驗證。</li><li><strong>自動化測試 (Automation)：</strong> 團隊目前採用 <strong>Robot Framework</strong> 執行自動化測試。相關環境建置請參閱自動化專案文件。</li></ul>',25)])])}const m=a(r,[["render",i]]);export{p as __pageData,m as default};
